<script>
    import { createEventDispatcher } from 'svelte';
    import agentInstructions from './AGENT_INSTRUCTIONS.md?raw';

    const dispatch = createEventDispatcher();

    let isOpen = false;
    let message = '';
    let loading = false;
    let error = '';

    let messages = [
        {
            role: 'assistant',
            content:
                'I am a color palette assistant here to help you build palettes. Try something like: "Create a calm diverging palette with 5 colors."'
        }
    ];

    function buildSystemPrompt() {
        return agentInstructions;
    }

    function describeAppliedConfig(config) {
        const modeLabel = config.mode === 'diverging' ? 'diverging' : 'sequential';
        const count = Math.max(2, Math.round(+config.numColors || 0));
        const bezierLabel = config.bezier ? 'on' : 'off';
        const lightnessLabel = config.correctLightness ? 'on' : 'off';
        return `Applied ${modeLabel} palette with ${count} colors (bezier ${bezierLabel}, lightness correction ${lightnessLabel}).`;
    }

    function extractPaletteConfig(text) {
        const codeBlockMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
        if (codeBlockMatch && codeBlockMatch[1]) {
            try {
                return JSON.parse(codeBlockMatch[1].trim());
            } catch (e) {
                // Fall through to looser parsing.
            }
        }

        const start = text.indexOf('{');
        const end = text.lastIndexOf('}');
        if (start !== -1 && end !== -1 && end > start) {
            try {
                return JSON.parse(text.substring(start, end + 1));
            } catch (e) {
                return null;
            }
        }

        return null;
    }

    async function sendMessage() {
        const prompt = message.trim();
        if (!prompt || loading) return;

        error = '';
        messages = [...messages, { role: 'user', content: prompt }];
        message = '';

        loading = true;
        try {
            const promptForModel = buildSystemPrompt();
            const conversation = messages.filter(m => m.role === 'user' || m.role === 'assistant');
            const response = await fetch('/api/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    messages: conversation,
                    systemPrompt: promptForModel
                })
            });

            const data = await response.json().catch(() => ({}));
            const content = response.ok ? data.content : data.error || `Error (${response.status})`;

            if (!response.ok) {
                error = content;
                return;
            }

            const parsed = extractPaletteConfig(content);
            if (parsed) {
                dispatch('applyPalette', parsed);
                messages = [...messages, { role: 'assistant', content: describeAppliedConfig(parsed) }];
            } else {
                messages = [...messages, { role: 'assistant', content: content || 'I could not generate a response.' }];
            }
        } catch (e) {
            error = (e && e.message) || 'Request failed.';
        } finally {
            loading = false;
        }
    }

    function onMessageKeydown(event) {
        if (event.key === 'Enter' && !event.shiftKey) {
            event.preventDefault();
            sendMessage();
        }
    }
</script>

<button class="chat-toggle" on:click={() => (isOpen = !isOpen)} title="AI palette assistant">
    <svg
        class="chat-icon"
        width="20"
        height="20"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round">
        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"></path>
    </svg>
    <span class="chat-label">{isOpen ? 'Close' : 'Ask AI'}</span>
</button>

{#if isOpen}
    <div class="chat-panel">
        <div class="chat-messages">
            {#each messages as msg}
                <div class="bubble {msg.role}">
                    <div class="role">{msg.role === 'user' ? 'You' : 'AI'}</div>
                    <div class="content">{msg.content}</div>
                </div>
            {/each}
        </div>

        {#if error}
            <div class="chat-error">{error}</div>
        {/if}

        <div class="chat-input">
            <textarea
                rows="1"
                bind:value={message}
                placeholder='Describe the palette…'
                on:keydown={onMessageKeydown} />
            <button class="send-btn" disabled={loading} on:click={sendMessage}>
                {loading ? '...' : 'Send'}
            </button>
        </div>
    </div>
{/if}

<style>
    .chat-toggle {
        position: fixed;
        right: 24px;
        bottom: 24px;
        z-index: 1000;
        padding: 0 16px 0 12px;
        height: 48px;
        border-radius: 999px;
        border: none;
        background: #4b6cb7;
        color: #fff;
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 8px;
        cursor: pointer;
        box-shadow: 0 4px 14px rgba(75, 108, 183, 0.4);
        font-size: 0.95rem;
        font-weight: 600;
        font-family: inherit;
    }
    .chat-toggle:hover {
        background: #3d5a9e;
    }
    .chat-toggle .chat-icon {
        flex-shrink: 0;
    }
    .chat-toggle .chat-label {
        white-space: nowrap;
    }

    .chat-panel {
        position: fixed;
        right: 24px;
        bottom: 84px;
        width: 340px;
        max-width: calc(100vw - 32px);
        height: 480px;
        max-height: calc(100vh - 110px);
        display: flex;
        flex-direction: column;
        z-index: 1000;
        border-radius: 16px;
        background: rgba(255, 255, 255, 0.85);
        -webkit-backdrop-filter: blur(20px);
        backdrop-filter: blur(20px);
        border: 1px solid rgba(0, 0, 0, 0.06);
        box-shadow: 0 16px 48px rgba(0, 0, 0, 0.12);
        overflow: hidden;
    }

    .chat-messages {
        flex: 1;
        overflow: auto;
        padding: 16px;
    }

    .bubble {
        margin-bottom: 10px;
        padding: 10px 12px;
        border-radius: 12px;
    }

    .bubble.user {
        background: rgba(75, 108, 183, 0.1);
    }

    .bubble.assistant {
        background: rgba(0, 0, 0, 0.03);
    }

    .role {
        font-size: 11px;
        font-weight: 600;
        color: #9ca3af;
        text-transform: uppercase;
        letter-spacing: 0.04em;
        margin-bottom: 3px;
    }

    .content {
        white-space: pre-wrap;
        font-size: 13px;
        line-height: 1.45;
        color: #374151;
    }

    .chat-error {
        color: #dc2626;
        font-size: 12px;
        padding: 0 16px 4px;
    }

    .chat-input {
        display: flex;
        align-items: stretch;
        gap: 8px;
        padding: 12px 16px;
        border-top: 1px solid rgba(0, 0, 0, 0.05);
    }

    .chat-input textarea {
        flex: 1;
        resize: vertical;
        max-height: 120px;
        border: 1px solid #e5e7eb;
        border-radius: 10px;
        padding: 6px 10px;
        font-size: 13px;
        font-family: inherit;
        line-height: 1.4;
        background: #fff;
        margin: 0;
        min-height: 36px;
    }
    .chat-input textarea:focus {
        outline: none;
        border-color: #4b6cb7;
    }

    .send-btn {
        padding: 0 14px;
        border: none;
        border-radius: 10px;
        background: #4b6cb7;
        color: #fff;
        font-size: 16px;
        font-weight: 600;
        cursor: pointer;
        white-space: nowrap;
        margin: 0;
        min-width: 64px;
        display: flex;
        align-items: center;
        justify-content: center;
    }
    .send-btn:hover {
        background: #3d5a9e;
    }
    .send-btn:disabled {
        opacity: 0.5;
        cursor: not-allowed;
    }
</style>
